SELECT cluster_name, total_memory, AVG(num_nodes) AS avg_nodes
FROM hpc_clusters
GROUP BY cluster_name, total_memory;

SELECT cluster_name, num_nodes, total_memory
FROM hpc_clusters
ORDER BY num_nodes DESC;

SELECT SUM(num_cores) AS total_cores, SUM(num_nodes) AS total_nodes
FROM hpc_clusters
WHERE location = 'New York';

SELECT cluster_name, total_memory
FROM hpc_clusters
ORDER BY total_memory DESC;

SELECT cluster_name, num_nodes
FROM hpc_clusters
WHERE num_nodes > 100;

SELECT admin_name
FROM system_admins
ORDER BY admin_id DESC;

SELECT admin_name, email
FROM system_admins
ORDER BY admin_name;
